// ================ 规则监控器实现 ================
class RuleValidator {
    static validateGameState(stackSys, slotCtrl) {
        try {
            // 断言1: 槽位容量限制
            if (slotCtrl.slots.filter(s => s !== null).length > 7) {
                throw new Error("槽位超容异常");
            }

            // 断言2: 仅可见卡片可操作
            const allCards = document.querySelectorAll('.card');
            allCards.forEach(card => {
                const isVisible = stackSys.isCardVisible(card.id);
                const isInteractive = !card.style.pointerEvents || card.style.pointerEvents === 'auto';

                if (isVisible && !isInteractive) {
                    console.error(`【规则破坏】可见卡片${card.id}不可点击`, card);
                    card.style.pointerEvents = 'auto'; // 修复状态
                }
                if (!isVisible && isInteractive) {
                    console.error(`【规则破坏】隐藏卡片${card.id}仍可点击`, card);
                    card.style.pointerEvents = 'none'; // 强制修正
                }
            });

            // 断言3: 有效消除验证
            const typeCounts = {};
            slotCtrl.slots.forEach(slot => {
                if (slot && slot.type) {
                    typeCounts[slot.type] = (typeCounts[slot.type] || 0) + 1;
                }
            });

            Object.values(typeCounts).forEach(count => {
                if (count > 7) { // 单类型不可能超过7张（理论极限）
                    throw new Error(`卡片类型分布异常: ${JSON.stringify(typeCounts)}`);
                }
            });

            return true;
        } catch (error) {
            console.error("🔥 规则校验失败:", error.message);
            alert(`游戏异常: ${error.message}\n已尝试自动恢复`);
            return false;
        }
    }

    // 每次关键操作后运行
    static monitorOperations() {
        setInterval(() => {
            RuleValidator.validateGameState(stackSystem, slotController);
        }, 5000); // 每5秒主动检查
    }
}

// ================ 边界案例处理器 ================
class BoundaryCaseHandler {
    static setupHandlers() {
        // 场景1: 槽位第7张触发消除
        slotController.onBeforeAdd = (cardId) => {
            if (slotController.isFull()) {
                // 预先检查是否能消除
                const tempSlots = [...slotController.slots, {type: document.getElementById(cardId).dataset.type}];
                return BoundaryCaseHandler.canFormTriple(tempSlots);
            }
            return true;
        };

        // 场景2: 连续快速点击防护
        let lastClickTime = 0;
        document.getElementById('gameBoard').addEventListener('click', (e) => {
            const now = Date.now();
            if (now - lastClickTime < 300) { // 300ms内多次点击视为无效
                e.stopPropagation();
                e.preventDefault();
                console.log("🛡️ 快速连点拦截");
                return false;
            }
            lastClickTime = now;
        }, true);
    }

    static canFormTriple(slots) {
        const counts = {};
        slots.forEach(slot => {
            if (slot?.type) {
                counts[slot.type] = (counts[slot.type] || 0) + 1;
            }
        });
        return Object.values(counts).some(count => count >= 3);
    }
}

