class PlayerExperienceGuard {
    constructor() {
        this.hintUsedCount = 0;
        this.lastActionTime = Date.now();
        this.actionTimer = null;

        // 创建提示按钮
        this.createHintButton();
        this.setupStagnationMonitor();
    }

    createHintButton() {
        const controlsDiv = document.querySelector('.controls');
        const hintBtn = document.createElement('button');
        hintBtn.id = 'hintBtn';
        hintBtn.textContent = `提示 (${this.hintUsedCount}/3)`;
        hintBtn.style.backgroundColor = '#6c757d';
        hintBtn.addEventListener('click', () => this.provideHint());
        controlsDiv.insertBefore(hintBtn, controlsDiv.firstChild);
    }

    setupStagnationMonitor() {
        // 每30秒检查无操作
        this.actionTimer = setInterval(() => {
            if (Date.now() - this.lastActionTime > 30000 && !GameState.isGameOver) {
                this.triggerStagnationWarning();
            }
        }, 5000);
    }

    recordPlayerAction() {
        this.lastActionTime = Date.now();
    }

    triggerStagnationWarning() {
        if (this.hintUsedCount < 3) {
            const hintBtn = document.getElementById('hintBtn');
            hintBtn.style.animation = 'pulse 1s infinite';

            // 10秒后自动停止提醒
            setTimeout(() => {
                hintBtn.style.animation = '';
            }, 10000);
        }
    }

    provideHint() {
        if (this.hintUsedCount >= 3 || GameState.isGameOver) return;

        // 寻找可消除组合
        const visibleCards = Array.from(document.querySelectorAll('.card'))
            .filter(card => window.getComputedStyle(card).pointerEvents !== 'none');

        const typeGroups = {};
        visibleCards.forEach(card => {
            const type = card.dataset.type;
            if (!typeGroups[type]) typeGroups[type] = [];
            typeGroups[type].push(card);
        });

        // 找到至少有3张的类型
        const hintType = Object.keys(typeGroups).find(type => typeGroups[type].length >= 3);

        if (hintType) {
            typeGroups[hintType].slice(0, 3).forEach(card => {
                card.style.boxShadow = '0 0 0 4px yellow';
                setTimeout(() => {
                    card.style.boxShadow = '';
                }, 3000);
            });

            this.hintUsedCount++;
            document.getElementById('hintBtn').textContent = 
                `提示 (${this.hintUsedCount}/3)`;
            console.log(`💡 提示生效: 点击3张${hintType}卡片`);
        }; else {
            alert("暂时没有明显可消除组合，请继续探索!");
        }
    }
}

