// ================ 自动化质量门禁 ================
class QualityGate {
    static validateModule(module, contract) {
        const missing = [];
        contract.required.forEach(method => {
            if (typeof module[method] !== 'function') missing.push(method);
        });

        if (missing.length > 0) {
            throw new Error(`模块验证失败: 缺少方法 ${missing.join(', ')}`);
        }
        console.log(`✅ ${module.constructor.name} 通过契约验证`);
    }

    static performanceCheck() {
        const metrics = window.eventBus.performanceMetrics;
        const avgRenderTime = metrics.renderTimes.length > 0 
            ? metrics.renderTimes.reduce((a, b) => a + b, 0) / metrics.renderTimes.length 
            : 0;

        const memoryUsage = metrics.memoryUsage.slice(-10); // 取最近10次
        const avgMemory = memoryUsage.length > 0 
            ? memoryUsage.reduce((a, b) => a + b, 0) / memoryUsage.length 
            : 0;

        return {
            renderScore: Math.max(0, 90 - avgRenderTime * 0.8), // 渲染性能分
            memoryScore: Math.max(0, 90 - avgMemory / 10),      // 内存性能分
            interactionCount: metrics.interactions
        };
    }
}

