**优化方案**：
```javascript
// 局部更新替代全量计算
updateVisibilityAfterRemoval(x, y) {
    const key = `${x}-${y}`;
    if (this.layout.get(key)?.length > 0) {
        const topCard = this.layout.get(key)[this.layout.get(key).length - 1];
        this.visibleCards.add(topCard.cardId);
    }

    // 检查相邻位置是否因本次操作而显露
    [[-1,0],[1,0],[0,-1],[0,1]].forEach(([dx,dy]) => {
        const neighborKey = `${x+dx}-${y+dy}`;
        if (this.layout.has(neighborKey)) {
